 1	import type { ClipboardEvent, FC } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  FormGroup,
 7	  Grid,
 8	  GridItem,
 9	  TextInput,
10	} from '@patternfly/react-core';
11	import { MinusCircleIcon } from '@patternfly/react-icons';
12	import { useForkliftTranslation } from '@utils/i18n';
13	
14	import type { LabelFields } from './utils/types';
15	
16	type LabelRowProps = {
17	  label: LabelFields;
18	  onChange: (label: LabelFields) => void;
19	  onDelete: (id: number) => void;
20	  isLabelsVisible: boolean;
21	};
22	
23	const LabelRow: FC<LabelRowProps> = ({ isLabelsVisible, label, onChange, onDelete }) => {
24	  const { t } = useForkliftTranslation();
25	  const { id, key, value } = label;
26	
27	  const handlePasteLabelKey = (event: ClipboardEvent<HTMLInputElement>): void => {
28	    event.preventDefault();
29	    const text = event.clipboardData.getData('text');
30	    const strings = text.split('=');
31	
32	    if (strings.length > 1) {
33	      onChange({ ...label, key: strings[0], value: strings[1] });
34	      return;
35	    }
36	
37	    onChange({ ...label, key: text });
38	  };
39	
40	  return (
41	    <Grid hasGutter rowSpan={2}>
42	      <GridItem span={6}>
43	        <FormGroup label={isLabelsVisible && t('Key')}>
44	          <TextInput
45	            aria-label={t('selector key')}
46	            data-testid="node-selector-key-input"
47	            isRequired
48	            onChange={(_event, newKey) => {
49	              onChange({ ...label, key: newKey });
50	            }}
51	            onPaste={handlePasteLabelKey}
52	            placeholder={t('Key')}
53	            type="text"
54	            value={key}
55	          />
56	        </FormGroup>
57	      </GridItem>
58	      <GridItem span={5}>
59	        <FormGroup label={isLabelsVisible && t('Value')}>
60	          <TextInput
61	            aria-label={t('selector value')}
62	            data-testid="node-selector-value-input"
63	            isRequired
64	            onChange={(_event, newValue) => {
65	              onChange({ ...label, value: newValue });
66	            }}
67	            placeholder={t('Value')}
68	            type="text"
69	            value={value}
70	          />
71	        </FormGroup>
72	      </GridItem>
73	
74	      <GridItem span={1}>
75	        <FormGroup label={isLabelsVisible && ' '}>
76	          <Button
77	            onClick={() => {
78	              onDelete(id);
79	            }}
80	            variant={ButtonVariant.plain}
81	          >
82	            {<MinusCircleIcon />}
83	          </Button>
84	        </FormGroup>
85	      </GridItem>
86	    </Grid>
87	  );
88	};
89	
90	export default LabelRow;

